mapper.select:
SELECT t.site_code as siteCode, #{startTime} as dateShow, t.vip_grade_code as vipGradeCode, count( t.vip_grade_code ) as currentGradeNum FROM user_info t WHERE 1 = 1 and account_type = 2
AND site_code = #{siteCode}
AND created_time < #{endTime}
GROUP BY t.site_code, t.vip_grade_code order by t.vip_grade_code asc

select a.siteCode, a.vipGradeCode, sum(a.receiveBonus / IF(a.finalRate IS NULL,1,a.finalRate)) as receiveBonus from ( SELECT t.currency as currency, (select final_rate from site_currency_info where site_code = #{siteCode} and t.currency = currency_code) as finalRate, t.site_code as siteCode, t.vip_grade_code as vipGradeCode, sum( t.award_amount ) as receiveBonus FROM site_vip_award_record t WHERE 1 = 1 and account_type = 2
AND t.site_code = #{siteCode}
AND t.receive_time >= #{startTime}
AND t.receive_time < #{endTime}
AND t.receive_status = 1 group by t.currency, t.site_code, t.vip_grade_code ) a group by a.siteCode, a.vipGradeCode

SELECT t.site_code as siteCode, t.after_change as vipGradeCode, count( t.after_change ) as achieveNum FROM site_vip_change_record t, user_info t1 WHERE 1= 1 and t.user_id = t1.user_id and t1.account_type = 2
AND t.site_code = #{siteCode}
AND t.change_time >= #{startTime}
AND t.change_time < #{endTime}
AND t.change_type = 0 GROUP BY t.site_code, t.after_change

SELECT SUM(receive_bonus) As receiveBonus
FROM report_vip_info
where site_code = #{vo.siteCode}

    AND date_show = #{vo.startTime}


    AND vip_rank_code = #{vo.vipRankCode}


    AND vip_grade_code = #{vo.vipGradeCode}

select a.siteCode, a.vipGradeCode, sum(a.receiveBonus / IF(a.finalRate IS NULL,1,a.finalRate)) as receiveBonus from ( SELECT t.currency as currency, (select final_rate from site_currency_info where site_code = #{siteCode} and t.currency = currency_code) as finalRate, t.site_code as siteCode, t.vip_grade_code as vipGradeCode, sum( t.award_amount ) as receiveBonus FROM site_vip_award_record_v2 t WHERE 1 = 1 and account_type = 2
AND t.site_code = #{siteCode}
AND t.receive_time >= #{startTime}
AND t.receive_time < #{endTime}
AND t.receive_status = 1 group by t.currency, t.site_code, t.vip_grade_code ) a group by a.siteCode, a.vipGradeCode

SELECT t.site_code as siteCode, t.vip_now as vipGradeCode, count( t.vip_now ) as achieveNum FROM site_vip_change_record_cn t, user_info t1 WHERE 1= 1 and t.user_id = t1.user_id and t1.account_type = 2
AND t.site_code = #{siteCode}
AND t.created_time >= #{startTime}
AND t.created_time < #{endTime}
AND t.change_type = 0 GROUP BY t.site_code, t.vip_now
